// Minimal Cocos2d-js implementation for OCD Challenge 2 game
window.cc = window.cc || {};

// Core functionality
cc.game = {
    config: { showFPS: false },
    run: function(canvasId) {
        this._canvas = document.getElementById(canvasId);
        this._setup();
        if (this.onStart) this.onStart();
        return true;
    },
    _setup: function() {
        console.log("Game setup initialized");
    }
};

// Resolution policy
cc.ResolutionPolicy = {
    SHOW_ALL: 2,
    EXACT_FIT: 0,
    NO_BORDER: 1,
    FIXED_HEIGHT: 3,
    FIXED_WIDTH: 4
};

// View management
cc.view = {
    enableAutoFullScreen: function(enable) { return this; },
    setDesignResolutionSize: function(width, height, policy) { 
        console.log("Setting design resolution size:", width, height, policy);
        return this; 
    },
    resizeWithBrowserSize: function(enable) { return this; }
};

// Director
cc.director = {
    setDisplayStats: function(show) {},
    runScene: function(scene) {
        console.log("Running scene");
        if (scene && typeof scene.onEnter === 'function') {
            scene.onEnter();
        }
    }
};

// Basic classes
cc.Class = {};
cc.Class.extend = function(props) {
    var _super = this.prototype;
    
    // Instantiate a base class
    var prototype = Object.create(_super);
    
    // Copy the properties over
    for (var name in props) {
        prototype[name] = props[name];
    }
    
    // The constructor function
    var Class = function() {
        if (this.ctor) {
            this.ctor.apply(this, arguments);
        }
    };
    
    // Create a new Class that inherits from this class
    Class.prototype = prototype;
    Class.prototype.constructor = Class;
    Class.prototype._super = function(methodName) {
        return _super[methodName].bind(this);
    };
    
    // Add extend method to the new class
    Class.extend = cc.Class.extend;
    
    return Class;
};

cc.Scene = function() { 
    this.children = []; 
};
cc.Scene.prototype = {
    onEnter: function() {},
    addChild: function(child) { 
        this.children.push(child);
        return child;
    }
};
cc.Scene.extend = cc.Class.extend;

cc.Layer = function() { 
    this.children = []; 
};
cc.Layer.prototype = {
    _super: function(methodName) {
        // This is a placeholder, will be replaced by the extend method
        console.log("_super called for method:", methodName);
    },
    ctor: function() {
        // Base constructor
    },
    setBackground: function(color) {
        this.bgColor = color;
        return this;
    },
    addChild: function(child) { 
        this.children.push(child);
        return child;
    },
    attr: function(props) { 
        for (var key in props) {
            this[key] = props[key];
        }
        return this; 
    },
    delegate: function(obj, events, handler) {
        if (typeof events === 'string') {
            // Single event
            obj._eventHandler = handler;
        } else if (typeof events === 'object') {
            // Multiple events
            obj._eventHandlers = events;
        }
        return this;
    },
    undelegate: function(obj) {
        delete obj._eventHandler;
        delete obj._eventHandlers;
        return this;
    },
    fadeOut: function(duration) { 
        return { 
            then: function(callback) { 
                return { 
                    act: function() { 
                        if (callback) setTimeout(callback, duration * 1000); 
                    } 
                }; 
            } 
        }; 
    },
    removeFromParent: function(cleanup) {
        // Remove from parent's children array
        return this;
    }
};
cc.Layer.extend = cc.Class.extend;

cc.LayerColor = {
    create: function(color) {
        var layer = new cc.Layer();
        layer.setBackground(color);
        return layer;
    }
};

// Sprite functionality
cc.Sprite = function(filename) { 
    this.children = []; 
    this.filename = filename;
};
cc.Sprite.prototype = {
    addChild: function(child) { 
        this.children.push(child);
        return child;
    },
    setPosition: function(x, y) {
        this.x = x;
        this.y = y;
        return this;
    },
    setScale: function(scale) { 
        this.scale = scale;
        return this; 
    },
    setOpacity: function(opacity) {
        this.opacity = opacity;
        return this;
    },
    setAnchorPoint: function(x, y) {
        this.anchorX = x;
        this.anchorY = y;
        return this;
    },
    setCascadeOpacityEnabled: function(enabled) {
        this.cascadeOpacity = enabled;
        return this;
    },
    scaleTo: function(duration, scale) { 
        var self = this;
        setTimeout(function() {
            self.scale = scale;
        }, duration * 1000);
        return { 
            scaleTo: function(d, s) { 
                setTimeout(function() {
                    self.scale = s;
                }, d * 1000);
                return { 
                    delay: function(d) { 
                        return { 
                            repeat: function() { 
                                return { 
                                    act: function() {} 
                                }; 
                            } 
                        }; 
                    } 
                }; 
            } 
        }; 
    },
    delay: function(duration) { 
        return { 
            then: function(callback) { 
                return { 
                    act: function() { 
                        if (callback) setTimeout(callback, duration * 1000); 
                    } 
                }; 
            },
            fadeIn: function(duration) {
                return {
                    act: function() {}
                };
            }
        }; 
    },
    fadeIn: function(duration) { 
        return { 
            act: function() {} 
        }; 
    },
    removeFromParent: function(cleanup) {
        // Remove from parent's children array
        return this;
    }
};

// Button functionality
cc.Button = {
    create: function(filename, options) {
        var button = new cc.Sprite(filename);
        if (options) {
            if (options.xy) button.setPosition(options.xy[0], options.xy[1]);
            if (options.scale) button.setScale(options.scale);
            if (options.opacity !== undefined) button.setOpacity(options.opacity);
        }
        return button;
    }
};

// Helper functions
cc.createSprite = function(name, options) {
    var sprite;
    if (name && name.charAt(0) === '@') {
        // Create a label
        sprite = new cc.LabelTTF(name.substr(1), "Arial", options && options.fontSize || 20);
        if (options && options.color) sprite.setColor(cc.color(options.color));
    } else {
        // Create a sprite
        sprite = new cc.Sprite('#' + name);
    }
    
    if (options) {
        if (options.xy) sprite.setPosition(options.xy[0], options.xy[1]);
        if (options.scale) sprite.setScale(options.scale);
        if (options.opacity !== undefined) sprite.setOpacity(options.opacity);
        if (options.anchor) sprite.setAnchorPoint(options.anchor[0], options.anchor[1]);
        if (options.size) {
            sprite.width = options.size[0];
            sprite.height = options.size[1];
        }
        if (options.textAlign) sprite.textAlign = options.textAlign;
    }
    
    return sprite;
};

cc.random = function(array, count) {
    if (!array || array.length === 0) return [];
    
    if (count === undefined) {
        return array[Math.floor(Math.random() * array.length)];
    } else {
        var shuffled = array.slice(0), i = array.length, min = i - count, temp, index;
        while (i-- > min) {
            index = Math.floor((i + 1) * Math.random());
            temp = shuffled[index];
            shuffled[index] = shuffled[i];
            shuffled[i] = temp;
        }
        return shuffled.slice(min);
    }
};

cc.tmpl = function(str, data) {
    return str.replace(/\{([^\}]+)\}/g, function(match, key) {
        return data[key] !== undefined ? data[key] : match;
    });
};

// Color utilities
cc.color = function(colorStr) {
    return colorStr;
};

// Text rendering
cc.LabelTTF = function(text, fontName, fontSize) {
    this.text = text;
    this.fontName = fontName;
    this.fontSize = fontSize;
    this.children = [];
};
cc.LabelTTF.prototype = {
    setString: function(text) { 
        this.text = text; 
        return this;
    },
    setColor: function(color) {
        this.color = color;
        return this;
    },
    addChild: function(child) { 
        this.children.push(child); 
        return child;
    },
    setPosition: function(x, y) {
        this.x = x;
        this.y = y;
        return this;
    }
};

// Resource loading
cc.LoaderScene = {
    preload: function(resources, callback, target) {
        console.log("Loading resources:", resources);
        setTimeout(function() {
            if (callback) callback.call(target);
        }, 500);
    }
};

// Sprite frame cache
cc.spriteFrameCache = {
    addSpriteFrames: function(jsonFile, imageFile) {
        console.log("Loading sprite frames from", jsonFile, "and", imageFile);
    }
};

// Missing classes (polyfills)
cc.OrbitCamera = function() {};
cc.CatmullRomBy = function() {};
cc.CatmullRomTo = function() {};
cc.CardinalSplineBy = function() {};
cc.CardinalSplineTo = function() {};

console.log("Cocos2d-js minimal implementation loaded");